import axios from 'axios';

const backendURL = 'http://localhost:3000/api/achievements';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get all achievements
export const getAllAchievements = async () => {
    try {
        const response = await axios.get(backendURL);
        return response.data;
    } catch (error) {
        console.error('Get all achievements error:', error);
        throw error;
    }
};

// Create a new achievement
export const createAchievement = async (achievementData) => {
    try {
        const response = await axios.post(backendURL, achievementData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Create achievement error:', error);
        throw error;
    }
};

// Get achievement by ID
export const getAchievement = async (id) => {
    try {
        const response = await axios.get(`${backendURL}/${id}`);
        return response.data;
    } catch (error) {
        console.error('Get achievement error:', error);
        throw error;
    }
};

// Update achievement
export const updateAchievement = async (id, achievementData) => {
    try {
        const response = await axios.put(`${backendURL}/${id}`, achievementData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update achievement error:', error);
        throw error;
    }
};

// Delete achievement
export const deleteAchievement = async (id) => {
    try {
        const response = await axios.delete(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Delete achievement error:', error);
        throw error;
    }
};

// Unlock achievement
export const unlockAchievement = async (userId, achievementId) => {
    try {
        const response = await axios.post(`${backendURL}/unlock`, { userId, achievementId }, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Unlock achievement error:', error);
        throw error;
    }
};

// Get achievements by category
export const getAchievementsByCategory = async (category) => {
    try {
        const response = await axios.get(`${backendURL}/category/${category}`);
        return response.data;
    } catch (error) {
        console.error('Get achievements by category error:', error);
        throw error;
    }
};
